// Extrair token e montar datas
const loginData = $input.first().json;
const token = loginData.accessToken;

if (!token) throw new Error('Login falhou: ' + JSON.stringify(loginData));

// Data de ontem
const hoje = new Date();
const ontem = new Date(hoje);
ontem.setDate(hoje.getDate() - 1);

// Formato YYYYMMDD para o RHiD
const pad = (n) => String(n).padStart(2, '0');
const dataStr = `${ontem.getFullYear()}${pad(ontem.getMonth()+1)}${pad(ontem.getDate())}`;

console.log('[RHiD] Token OK. Data:', dataStr);

return [{
  json: {
    token,
    bearerHeader: `Bearer ${token}`,
    dataStr,      // ex: 20260521
    dataISO: ontem.toISOString().slice(0, 10)  // ex: 2026-05-21
  }
}];

// Extrair GUID do relatório gerado
const data = $input.first().json;
const tokenData = $('Extrair Token e Data').first().json;

if (!data.guid) throw new Error('GUID não retornado: ' + JSON.stringify(data));
if (data.error && data.error !== '') throw new Error('Erro ao gerar relatório: ' + data.error);

console.log('[RHiD] Relatório gerado. GUID:', data.guid, '| Pessoas:', data.numPeople);

return [{
  json: {
    guid: data.guid,
    numPeople: data.numPeople,
    token: tokenData.token,
    bearerHeader: tokenData.bearerHeader,
    dataISO: tokenData.dataISO,
    dataStr: tokenData.dataStr,
    tentativas: 0
  }
}];

// Processar CSV e preparar para enviar ao ERP Orbe
const csvText = $input.first().json;
const guidData = $('Extrair GUID').first().json;

console.log('[RHiD] CSV baixado. Tamanho:', String(csvText).length, 'chars');

// Converter CSV para array de objetos
const lines = String(csvText).split('\n').filter(l => l.trim());
if (lines.length < 2) {
  console.log('[RHiD] CSV vazio ou sem dados');
  return [];
}

// Detectar separador (;  ou ,)
const sep = lines[0].includes(';') ? ';' : ',';
const headers = lines[0].split(sep).map(h => h.trim().replace(/"/g, ''));

console.log('[RHiD] Colunas:', headers.join(', '));
console.log('[RHiD] Registros:', lines.length - 1);

const records = lines.slice(1).map(line => {
  const values = line.split(sep).map(v => v.trim().replace(/"/g, ''));
  const obj = {};
  headers.forEach((h, i) => { obj[h] = values[i] ?? ''; });
  return obj;
});

// Mapear para formato esperado pela Edge Function do ERP
const mapped = records
  .filter(r => r['Nome'] || r['nome'] || r['NOME'] || r['Person.name'] || Object.values(r)[0])
  .map(r => {
    const nome = r['Nome'] || r['nome'] || r['NOME'] || r['Person.name'] || Object.values(r)[0] || '';
    const data = guidData.dataISO;

    // Tentar mapear colunas de hora (podem variar por configuração)
    const getField = (...keys) => {
      for (const k of keys) {
        for (const [rk, rv] of Object.entries(r)) {
          if (rk.toLowerCase().includes(k.toLowerCase()) && rv) return rv;
        }
      }
      return null;
    };

    return {
      pessoa_nome: nome,
      pessoa_cpf: null,
      pessoa_matricula: null,
      empresa_rhid_nome: null,
      empresa_cnpj: null,
      data,
      entrada: getField('entrada', 'inicio', 'in'),
      saida_almoco: getField('saida_almoco', 'saida alm', 'almoco'),
      retorno_almoco: getField('retorno', 'retorno alm'),
      saida: getField('saida', 'fim', 'out'),
      horas_trabalhadas: getField('horas_trab', 'total hora', 'hr trab'),
      hora_extra: getField('extra', 'he '),
      falta: getField('falta'),
      atraso: getField('atraso'),
      _raw: r
    };
  });

console.log('[RHiD] Registros mapeados:', mapped.length);
return mapped.map(m => ({ json: m }));

const result = $input.first().json;
console.log('[RHiD→ERP] Resultado:', JSON.stringify(result));
return $input.all();

// Relatório ainda não concluído — loga e deixa o loop continuar
const status = $input.first().json;
console.log('[RHiD] Aguardando conclusão... percent:', status.percent, '%');
return $input.all();
